class OuterClass {
    private String message = "Hello from Outer";
    private static String staticMessage = "Static message";

    // 1. Non-static inner class (inner class)
    class InnerClass {
        void display() {
            // Can access outer class private members
            System.out.println("Inner: " + message);
            System.out.println("Inner: " + staticMessage);
            outerMethod();
        }
    }

    // 2. Static nested class
    static class StaticNestedClass {
        void display() {
            // Can't access instance members of outer class
            // System.out.println(message); // ERROR! Can't access non-static
            System.out.println("Static Nested: " + staticMessage);
        }
    }

    void outerMethod() {
        System.out.println("Outer method called");
    }

    // 3. Local inner class (inside a method)
    void localInnerExample() {
        class LocalInner {
            void display() {
                System.out.println("Local inner class");
            }
        }

        LocalInner local = new LocalInner();
        local.display();
    }

    // 4. Anonymous inner class
    Runnable getRunnable() {
        return new Runnable() {
            @Override
            public void run() {
                System.out.println("Anonymous inner class running");
            }
        };
    }
}

public class InnerClassesExample {
    public static void main(String[] args) {
        OuterClass outer = new OuterClass();

        // Create inner class instance
        OuterClass.InnerClass inner = outer.new InnerClass();
        inner.display();

        System.out.println("---");

        // Create static nested class instance
        OuterClass.StaticNestedClass staticNested = new OuterClass.StaticNestedClass();
        staticNested.display();

        System.out.println("---");

        outer.localInnerExample();

        System.out.println("---");

        Runnable runnable = outer.getRunnable();
        runnable.run();
    }
}

